import json, re
from collections import Counter
d=json.load(open('/home/polaris/wt/flywheel/outputs/baseline_routed_outline.json'))
CW=re.compile(r"[A-Za-z][A-Za-z0-9\-]{2,}")
STOP=frozenset({"the","and","for","that","this","with","from","have","has","had","was","were","are","been","will","would","could","should","their","there","these","those","which","while","when","where","what","who","whom","into","than","then","such","also","not","but","its","our","your","his","her","they","them","some","more","most","over","under","between","among","per","via","about","each","any","all"})
def words(t): return {w.lower() for w in CW.findall(t or "") if w.lower() not in STOP}
plansraw=[s for s in d if s['title']!='Additional Corroborated Findings']
resid=[s for s in d if s['title']=='Additional Corroborated Findings'][0]['evidence']
plans_tf=[(s['title'], words(s['title']+' '+s['focus'])) for s in plansraw]

# Eyeball Jaccard winners: sample rows routed to GenAI and Conclusions
def jrow(r):
    bw=words((r.get('title') or '')+' '+(r.get('quote') or ''))
    best=None;bs=0
    for t,pw in plans_tf:
        s=len(bw&pw)/len(bw|pw) if bw|pw else 0
        if s>bs: bs=s;best=(t,sorted(bw&pw))
    return best
shown={'Generative':0,'Conclusions':0}
for r in resid:
    b=jrow(r)
    if not b: continue
    for k in shown:
        if b[0].startswith(k) and shown[k]<5:
            shown[k]+=1
            print(f"[{k}] {b[1]} <- {r['title'][:75]}")
print()
# Distinctiveness-weighted plan signature: word weight = 1/#sections containing it (assigned rows), require score>=1.0
sigs=[]
for s in plansraw:
    sig=set()
    for r in s['evidence']:
        sig |= words((r.get('title') or '')+' '+(r.get('quote') or ''))
    sigs.append((s['title'],sig))
df=Counter()
for t,sig in sigs: df.update(sig)
c=Counter(); zero=0; ex=[]
for r in resid:
    bw=words((r.get('title') or '')+' '+(r.get('quote') or ''))
    best=None;bs=0.999
    for t,sig in sigs:
        sc=sum(1.0/df[w] for w in bw&sig if df[w]<=2)  # only words in <=2 section sigs
        if sc>bs: bs=sc;best=t
    if best is None: zero+=1
    else:
        c[best]+=1
        if len(ex)<10: ex.append((best[:28], r['title'][:60]))
print('DISTINCTIVE plan-sig (df<=2, score>=1): zero=',zero)
for t,x in c.most_common(): print(f'  {x:4d} {t[:60]}')
for b,t in ex: print('   ', b, '<-', t)
EOF
